var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"저건…… 기지를 습격했던 그 괴물인가?","JPN":"あれは……基地を襲ってきた化け物か？","ENG":"Isn’t that... the monster that attacked the base?","TWN":"那是……偷襲基地的怪物嗎？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"침식파 형태가 미세하게 달라, 동형 타입의 다른 개체인 것 같아!","JPN":"侵食波の形が微妙に違う、同型タイプの他の個体みたい！","ENG":"Seeing that the Corruption ray form is slightly different, it seems to be a different entity of the same type!","TWN":"和侵蝕波型態不太一樣，應該是不同類型的個體！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"2시 방향! 사령관님, 미확인 침식체들이 더 몰려옵니다!","JPN":"2時方向！　司令官、未確認侵食体がもっと押し寄せてきます！","ENG":"2 o’clock! Commander, more unidentified Corrupted Objects are heading our way!","TWN":"2點鐘方向！司令官，不明侵蝕體湧現！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"저 쪽은 인형들이로군요.","JPN":"あちらは人形たちですね。","ENG":"Those are puppets.","TWN":"你們那邊是木偶嗎？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"인형?","JPN":"人形？","ENG":"Puppets?","TWN":"木偶？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"네, 그런 취미를 가진 마왕의 수하들입니다. 저희는 인형의 창조자라고 부르죠.","JPN":"はい、そういう趣味を持った魔王の手下たちです。私たちは人形の創造者と呼んでいます。","ENG":"Yes, they are the minions of a Demon Lord who has such a hobby. We call her the Puppet Creator.","TWN":"是，那些是喜歡木偶的魔王手下，我們稱她為木偶的創造者。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_BOSS_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"그럼 최소 두 명의 마왕이 우리 뒤를 포위했다는 뜻인가?","JPN":"それでは少なくとも2人の魔王が私たちの後ろを囲んでいるということか？","ENG":"So you’re saying that at least two Demon Lords have surrounded us from the back?","TWN":"意思是至少有二個魔王包圍我們嗎？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_BOSS_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"별로 기분 좋은 소식은 아니군.","JPN":"それはあまり嬉しいニュースではないな。","ENG":"I was hoping for better news.","TWN":"這不是個好消息呢。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_BOSS_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"저로서도 의외입니다. 마왕들이 전장에서 손을 잡는 경우는 거의 없거든요.","JPN":"こちらとしても意外ですね。魔王たちが戦場で手を組むことはほとんどないので。","ENG":"I am also surprised. Demon Lords almost never join forces on the battlefield.","TWN":"我也感到很意外，魔王在戰場上幾乎不太會聯手的。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_BOSS_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"안타깝군. 적 선두 부대를 괴멸시킬 기회였는데.","JPN":"残念だ。敵の先鋒部隊を壊滅させるチャンスだったのに。","ENG":"That is unfortunate. It was our opportunity to wipe out the enemy’s vanguard.","TWN":"真可惜，原本有機會可以殲滅敵人的先鋒部隊。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L22_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"완전히 포위 당하기 전에 이 장소를 빠져나가야겠어.","JPN":"完全に囲まれる前にこの場所から抜け出すぞ。","ENG":"We should retreat before we’re completely surrounded.","TWN":"在完全受困前，必須趕快離開這個地方。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"……그건 곤란합니다.","JPN":"……それは困ります。","ENG":"...That would be difficult.","TWN":"……這可能有困難。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"무슨 뜻이지?","JPN":"どういうことだ？","ENG":"What do you mean?","TWN":"什麼意思？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L25_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"이 게임에는 룰이 있다고 말씀 드렸었죠.","JPN":"このゲームにはルールがあるとお話ししましたね。","ENG":"Do you remember that I mentioned there are rules to this game?","TWN":"我說過這個遊戲是有規則的。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L26_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"승리를 위한 규칙이 있다면, 패배를 위한 규칙도 있습니다.","JPN":"勝利のための規則があるなら、敗北のための規則もあります。","ENG":"If there are rules for victory, then there are rules for defeat as well.","TWN":"贏有贏的規則，輸也有輸的規則。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L30_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"어째서 제가 이곳 이면세계를 집결지로 하여 적을 요격하자고 말씀드렸는지 아십니까?","JPN":"どうして私がここ、裏世界を集結の場にして敵を迎撃しようと申し出たのか、その理由をご存じですか？","ENG":"Do you know why I designated Counterside as our rendezvous point to strike our enemies?","TWN":"你知道為什麼我會說先在異界這裡集合，再攻擊敵人嗎？"},"stage":{"bg":"MAINSTREAM_000006","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"그건…… 현실 세계의 피해를 줄이기 위해서가 아닌가?","JPN":"それは……現実世界の被害を減らすためではないのか？","ENG":"That... was it not to minimize the damage on Normalside?","TWN":"這……難道不是希望降低對現實世界的傷害嗎？"},"stage":{"bg":"MAINSTREAM_000006","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"물론 그런 부분도 있습니다.","JPN":"もちろんその理由もあります。","ENG":"That’s part of the reason, yes.","TWN":"這當然也是其中一個原因。"},"stage":{"bg":"MAINSTREAM_000006","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"하지만 전략적으로 보면 적을 현실 세계로 끌어들이는 편이 더 유리할 수도 있죠.","JPN":"ですが、戦略的に考えると敵を現実世界へ引き込んだ方がもっと有利になるかもしれません。","ENG":"However, from a strategic standpoint, it may be more advantageous to force our opponents to enter Normalside.","TWN":"但就戰略上而言，將敵人引到現實世界，或許對我們更有利。"},"stage":{"bg":"CCN_SHIP","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"저들의 준동을 확인한 전 세계가 비상 체제로 돌아설 것이고 더 많은 지원군을 확보할 수도 있을 테니까요.","JPN":"彼らの動きを見た全世界が非常体制に入り、もっと多くの支援軍を確保できるかもしれないのですから。","ENG":"After all, it would have been easier to gather reinforcements if the rest of the world saw their mobilization and entered a state of emergency.","TWN":"因為當全世界都發現敵人的目的，就會進入緊急狀態，也會有更多的援軍加入。"},"stage":{"bg":"CCN_SHIP","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"확실히 그런 부분도 있겠군. 그렇다면 어째서?","JPN":"確かにそれもありだな。ならどうしてだ？","ENG":"That makes sense. So why bring us here?","TWN":"你這麼說也沒錯，那究竟為何？"},"stage":{"bg":"CCN_SHIP","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"적들이 현실 세계에 도착하면 그것이 곧 우리들의 패배이기 때문입니다.","JPN":"敵が現実世界に到達すると、すなわちそれが私たちの負けになるからです。","ENG":"If the enemy enters Normalside, it is our defeat.","TWN":"因為當敵人抵達現實世界，就代表著我們的失敗。"},"stage":{"bg":"QLIPHOTH","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"뭐라고?","JPN":"なんだと？","ENG":"What?","TWN":"你說什麼？"},"stage":{"bg":"QLIPHOTH","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"저들은 이면세계 깊숙한 곳, 저들의 클리파 차원의 입구로부터 진군을 시작해야 합니다.","JPN":"彼らは裏世界の深いところ、彼らのクリファ次元の入り口から進軍を開始しなければなりません。","ENG":"They must start their advance from the entrance of the deepest part of Counterside known as the Qlipha Dimension.","TWN":"他們必須從異界深處，也就是逆卡巴拉次元的入口開始進軍。"},"stage":{"bg":"QLIPHOTH","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"공간 이동이나, 지름길 같은 편법은 사용할 수 없죠.","JPN":"空間移動や、近道などの便法は使えません。","ENG":"Expedients such as teleportation or shortcuts are not allowed.","TWN":"而且不能利用空間移動或走捷徑。"},"stage":{"bg":"QLIPHOTH","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그리고 그 진군을 통해 이면세계와 현실이 겹쳐지는 첫 번째 통로.","JPN":"そしてその進軍によって裏世界と現実が重なる第一通路。","ENG":"They must continue their advance until the first pathway of the border between Counterside and Normalside.","TWN":"當進軍到異界和現實世界交界的第一個通道，"},"stage":{"bg":"QLIPHOTH","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"흔히 제 1 대균열로 부르는 곳에 도달하면…… 승리하는 것입니다.","JPN":"よく第1大亀裂と呼ばれる場所に着くと……勝利するのです。","ENG":"If they reach what is commonly called the 1st Grand Dimension Crevice, it is their victory.","TWN":"也就是常說的第一大峽谷時……就代表他們獲勝。"},"stage":{"bg":"QLIPHOTH","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"제 1 대균열……? 설마 그라운드 원 말인가?","JPN":"第1大亀裂……？　まさかグラウンド・ワンのことか？","ENG":"The 1st Grand Dimension Crevice...? You mean Ground One?","TWN":"第一大峽谷……？該不會就是指G1？"},"stage":{"bg":"GROUND_ONE","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그렇습니다. 그래서 그곳이 관리국 직할도시로 유지되고 있는 거죠.","JPN":"そうです。それこそがそこを管理局の直轄都市として維持している理由です。","ENG":"That is correct. This is why a city under the direct control of the Administration has been established there.","TWN":"沒錯，所以那個地方才會一直是管理局的直轄市。"},"stage":{"bg":"GROUND_ONE","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"만약 우리가 여기서 더 퇴각하거나 적을 저지하는데 실패하면……","JPN":"もし私たちがここからもっと後ろへ退却したり、敵の阻止に失敗すると……","ENG":"If we retreat further or fail to stop the enemy here...","TWN":"若是我們再繼續退，或是阻止敵人失敗……"},"stage":{"bg":"GROUND_ONE","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"게임에서 패배하겠군.","JPN":"ゲームに負けることになると。","ENG":"We will lose the game.","TWN":"那我們就會輸掉遊戲嗎？"},"stage":{"bg":"GROUND_ONE","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"그럼 승리를 위한 규칙은 뭐지?","JPN":"それでは勝利のための規則はなんだ？","ENG":"Then what are the rules for victory?","TWN":"那贏的規則又是什麼？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L8_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"반대로 저희가 이면세계 깊숙한 곳, 저들의 성역인 클리파 차원에 도달하여 이 세계와의 통로를 파괴하는 것입니다.","JPN":"逆に私たちが裏世界の深いところ、彼らの聖域であるクリファ次元に到達してこの世界との通路を破壊することです。","ENG":"Conversely, we must reach the deepest part of Counterside, their sanctuary, the Qlipha Dimension, and destroy the pathway with this world.","TWN":"就是相反過來，我們要抵達異界深處，也就是聖域 逆卡巴拉次元，再破壞掉通往世界的通道。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L9_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"물론 붕괴된 통로는 시간이 지나면 다시 생성되지만, 적어도 마왕과 직접 싸우지 않고 종말을 유예할 수 있는 유일한 방법이죠.","JPN":"もちろん崩壊した通路は時間が経つと再生成されますが、少なくとも魔王と直接戦わず、終焉を猶予できる唯一の方法です。","ENG":"The collapsed pathway will gradually rebuild itself, but it is the only way to postpone the apocalypse without engaging in direct combat with a Demon Lord.","TWN":"雖然破壞掉的通道，過一段時間後又會再產生，但這是唯一不需要直接跟魔王交手，又可以拖延末日到來的方法。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L10_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"그렇다는 건 결국 이대로 포위당한 채 우세한 적과 싸워야 한다는 건가?","JPN":"ということは、結局こうして囲まれたまま優位に立っている敵と戦わなければならないのか？","ENG":"So, in conclusion, we need to fight stronger enemies while being surrounded like this?","TWN":"所以你的意思就是，我們必須在被包圍的情況下，和居於優勢的敵人開戰？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L11_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"요약하자면 그렇습니다.","JPN":"要するにそういうことです。","ENG":"In a nutshell, that is correct.","TWN":"簡單來說是這樣沒錯。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L12_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"……힘든 싸움이 되겠군.","JPN":"……厳しい闘いになるな。","ENG":"...This will be a difficult fight.","TWN":"……看來會是場硬仗。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_DESPAIR"}}}}]`);export{e as default};